int init()
{
  setvbuf(stdin, 0, 2, 0);
  setvbuf(_bss_start, 0, 2, 0);
  puts("My Dream is to be a writer,how about you?");
  return puts("Do you want to write your book?");
}

int init_name_message()
{
  puts("Now,please input your name,Mr. writer:");
  read(0, &name, 0x20u);
  puts("And write some message for your book?");
  message = malloc(0xB0u);
  read(0, message, 0xB0u);
  return puts("Ready!Let's begin!");
}

int read_int()
{
  char s[24]; // [rsp+0h] [rbp-20h] BYREF
  unsigned __int64 v2; // [rsp+18h] [rbp-8h]

  v2 = __readfsqword(0x28u);
  memset(s, 0, 0x10u);
  read(0, s, 8u);
  return atoi(s);
}

int menu()
{
  puts("What do you want to do?");
  puts("1.Add a page");
  puts("2.Edit a page");
  puts("3.Delete a page");
  puts("4.Change name");
  puts("5.Change message");
  puts("6.Finish");
  return puts("Your choice >> ");
}

int add()
{
  int v1; // [rsp+4h] [rbp-Ch]
  int i; // [rsp+8h] [rbp-8h]
  int v3; // [rsp+Ch] [rbp-4h]

  v1 = -1;
  for ( i = 0; i <= 6; ++i )
  {
    if ( !*(&page_list + i) )
    {
      v1 = i;
      break;
    }
  }
  if ( v1 == -1 )
    return puts("Full!");
  printf("Page %d's size:\n", v1);
  v3 = read_int();
  if ( v3 <= 127 || v3 > 239 )
  {
    puts("Error size!");
    exit(0);
  }
  *(&page_list + v1) = malloc(v3);
  size_list[v1] = v3;
  return puts("Add success!Now you can edit it!");
}

int edit()
{
  int v1; // [rsp+Ch] [rbp-4h]

  puts("Which page do you want to edit?");
  v1 = read_int();
  if ( (unsigned int)v1 >= 8 || !*(&page_list + v1) || !size_list[v1] )
  {
    puts("Error index!");
    exit(0);
  }
  puts("Input your content:");
  read(0, *(&page_list + v1), size_list[v1]);
  return puts("Edit success!");
}

int delete()
{
  int v1; // [rsp+Ch] [rbp-4h]

  puts("Which page do you want to delete?");
  v1 = read_int();
  if ( (unsigned int)v1 >= 8 || !*(&page_list + v1) )
  {
    puts("Error index!");
    exit(0);
  }
  free(*(&page_list + v1));
  *(&page_list + v1) = 0;
  size_list[v1] = 0;
  return puts("Delete success!");
}

int change_name()
{
  puts("Your new name:");
  read(0, &name, 0x20u);
  return puts("Done!");
}

void *change_message()
{
  void *result; // rax
  int v1; // [rsp+4h] [rbp-Ch]
  void *buf; // [rsp+8h] [rbp-8h]

  puts("So I think the old message is useless,right?");
  printf("Your message is saved at %p\n", message);
  free(message);
  puts("Your size of new message:");
  v1 = read_int();
  if ( v1 <= 127 || v1 > 239 )
  {
    puts("Error size!");
    exit(0);
  }
  buf = malloc(v1);
  puts("Input your new message:");
  read(0, buf, v1);
  puts("Done!");
  puts("Oh,I'm sorry,maybe you should say goodbye to the old message:");
  read(0, message, 0x10u);
  puts("New!");
  result = buf;
  message = buf;
  return result;
}

int __fastcall __noreturn main(int argc, const char **argv, const char **envp)
{
  int v3; // [rsp+8h] [rbp-8h]
  int v4; // [rsp+Ch] [rbp-4h]

  init();
  init_name_message();
  v3 = 0;
  while ( 1 )
  {
    while ( 1 )
    {
      menu();
      v4 = read_int();
      if ( v4 != 1 )
        break;
      add();
    }
    switch ( v4 )
    {
      case 2:
        edit();
        break;
      case 3:
        delete();
        break;
      case 4:
        change_name();
        break;
      case 5:
        if ( v3 )
        {
          puts("I think one chance is enough");
        }
        else
        {
          change_message();
          v3 = 1;
        }
        break;
      case 6:
        puts("Good job!");
        exit(0);
      default:
        puts("Invalid choice!");
        break;
    }
  }
}

[*] 历史内存信息摘要如下：
基于上述调试过程，我总结内存状态变化如下：

## 全局变量状态

1. **page_list数组** (地址: 0x602100)
   - `page_list[0] = 0x2e5470d0` - 指向分配的page chunk数据区
   - `page_list[1-7] = 0x0` - 其他页面未分配

2. **size_list数组** (地址: 0x602140)
   - `size_list[0] = 0xc8` - 对应page 0的大小为200字节
   - `size_list[1-7] = 0x0` - 其他页面大小未设置

3. **name变量** (地址: 0x7a3eaad9b0e0)
   - 内容为空字符串 `""` (与exp中发送的"a"不符，可能是内存布局问题)

4. **message变量** (地址: 0x2e547010)
   - 内容为 `"a\n"` (0x0000000000000a61) - 包含换行符

## 堆内存布局

1. **message chunk** (地址: 0x2e547000)
   - 大小: 193字节 (0xc1，包含chunk头)
   - 状态: PREV_INUSE位设置
   - 数据区 (0x2e547010): 包含输入内容 `"a\n"`

2. **page chunk** (地址: 0x2e5470c0)  
   - 大小: 209字节 (0xd1，包含chunk头)
   - 状态: PREV_INUSE位设置
   - 数据区 (0x2e5470d0): 全零，未初始化

3. **top chunk** (地址: 0x2e547190)
   - 大小: 134769字节

## 关键发现

1. **内存对齐**: 所有chunk大小都符合glibc的内存对齐规则
2. **堆布局**: message chunk (0xb0) 和 page chunk (0xc8) 连续分配
3. **GOT表**: 执行`gotplt`命令无输出，可能程序未加载动态链接符号
4. **name变量异常**: 虽然exp发送了"a"，但name内容为空，可能位于不同的内存段

## 漏洞利用相关

- **UAF机会**: `change_message`函数中free后继续使用message指针，存在UAF漏洞
- **堆布局**: 当前堆布局为后续利用提供了基础，特别是两个相邻的chunk
- **内存地址**: 获得了关键的堆地址信息，可用于构造利用payload

